import { tickFilterMap } from './tick-filter-mapping';
import { NUMERIC_DATATYPE } from '../../core/datatype-constants';

export function ZC_AXIS_TICK_FILTER(args) {
    let chart = this,
        column = args.columnInfo.data[0],
        axisType = args.axisType,
        event = args.event;

    //supports only for ORDINAL datatype
    if (column.datatype == NUMERIC_DATATYPE) {
        return;
    }

    if (!chart.cache.hierarchical) {
        chart.cache.hierarchical = {
            row: {},
            column: {}
        };
    }

    let selection = tickFilterMap._defaultBehavior.selection.call(this, args);

    tickFilterMap._defaultBehavior.action.call(this, selection);
}
